import{_ as a,c as i,o as t,ag as o}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"Dori Find Models","description":"","frontmatter":{},"headers":[],"relativePath":"Dori.md","filePath":"Dori.md"}'),r={name:"Dori.md"};function n(l,e,s,d,u,c){return t(),i("div",null,e[0]||(e[0]=[o('<h1 id="dori-find-models" tabindex="-1">Dori Find Models <a class="header-anchor" href="#dori-find-models" aria-label="Permalink to &quot;Dori Find Models&quot;">​</a></h1><p><strong>Dori Find Models</strong> is DGrid’s natural-language–driven assistant for discovering and evaluating large language models (LLMs). Using Dori, you express your requirements in plain English, test shortlisted models with your own workloads, and receive structured reports to support confident, data-backed model choices.</p><h2 id="role-in-the-dgrid-platform" tabindex="-1">Role in the DGrid Platform <a class="header-anchor" href="#role-in-the-dgrid-platform" aria-label="Permalink to &quot;Role in the DGrid Platform&quot;">​</a></h2><p>Dori is one of two tightly integrated capabilities in the DGrid ecosystem:</p><ul><li><strong>Dori Find Models</strong> – Helps you: <ul><li>Translate business or product requirements into concrete model candidates</li><li>Discover, test, and compare models in a guided, conversational flow</li></ul></li><li><strong>AI Gateway</strong> – Provides: <ul><li>A single abstraction layer and API over 200+ production-ready LLMs</li><li>Configuration-based model choice and switching, without code changes</li></ul></li></ul><p>Together, they enable an end-to-end LLM workflow:</p><blockquote><p><strong>Traditional:</strong> Search vendors → create many accounts → test manually → integrate per-vendor</p><p><strong>With DGrid (Dori + AI Gateway with LLM Marketplace):</strong> Describe needs → discover &amp; test in one place → integrate once → swap models via config</p></blockquote><h2 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h2><h3 id="_1-natural-language-requirements-intake" tabindex="-1">1. Natural-Language Requirements Intake <a class="header-anchor" href="#_1-natural-language-requirements-intake" aria-label="Permalink to &quot;1. Natural-Language Requirements Intake&quot;">​</a></h3><p>Dori starts from your real-world needs, captured in free-form text. For example:</p><ul><li>“We need a low-latency, cost-efficient model for multilingual customer support (English, Spanish, Portuguese), integrated into our existing chatbot.”</li><li>“We’re building a code assistant focusing on Python and TypeScript; strong reasoning and large-context understanding are important.”</li><li>“We want a model optimized for long-document RAG, with stable performance on 10k+ token contexts.”</li></ul><p>You do <strong>not</strong> need to know exact model names, providers, or benchmark acronyms. Dori interprets your description and translates it into technical selection criteria.</p><h3 id="_2-intelligent-search-across-the-llm-marketplace" tabindex="-1">2. Intelligent Search Across the LLM Marketplace <a class="header-anchor" href="#_2-intelligent-search-across-the-llm-marketplace" aria-label="Permalink to &quot;2. Intelligent Search Across the LLM Marketplace&quot;">​</a></h3><p>Once your requirements are captured, Dori searches across the ​<strong>DGrid LLM Marketplace</strong>​, which aggregates 200+ LLMs behind a single interface.</p><p>Dori:</p><ul><li>Filters candidate models by: <ul><li><strong>Task fit</strong> (e.g., chat, code, RAG, multi-lingual support)</li><li><strong>Context window</strong> (short vs long context, e.g., 10k+ tokens)</li><li><strong>Latency and cost profiles</strong></li><li>Other relevant operational characteristics</li></ul></li><li>Ranks models according to your priorities: <ul><li>Throughput and latency sensitivity</li><li>Quality vs cost tradeoffs</li><li>Specific capability needs (e.g., coding, reasoning, multilinguality)</li></ul></li><li>Returns a ​<strong>short, relevant list of recommended models</strong>​, so you avoid manually inspecting dozens of vendor pages and benchmark tables.</li></ul><h3 id="_3-unified-real-workload-testing" tabindex="-1">3. Unified, Real-Workload Testing <a class="header-anchor" href="#_3-unified-real-workload-testing" aria-label="Permalink to &quot;3. Unified, Real-Workload Testing&quot;">​</a></h3><p>After Dori proposes a shortlist, it helps you test those models in a ​<strong>single environment</strong>​, within DGrid:</p><ul><li>Run <strong>trials</strong> on candidate models directly in the platform</li><li>Use <strong>your own prompts, documents, and scenarios</strong> instead of generic examples</li><li>Evaluate models under a ​<strong>shared, consistent setup</strong>​, making comparisons meaningful</li></ul><p>This eliminates the common pattern of:</p><ul><li>Separate vendor playgrounds</li><li>Ad-hoc scripts for each API</li><li>Screenshots, notes, and spreadsheets spread across tools</li></ul><h3 id="_4-structured-shareable-evaluation" tabindex="-1">4. Structured, Shareable Evaluation <a class="header-anchor" href="#_4-structured-shareable-evaluation" aria-label="Permalink to &quot;4. Structured, Shareable Evaluation&quot;">​</a></h3><p>Dori produces clear, structured outputs that you can share and discuss with your team, such as:</p><ul><li><strong>Example outputs</strong> from each candidate model</li><li><strong>Qualitative notes</strong> about behavior and suitability</li><li><strong>Latency and performance metrics</strong> observed during tests</li><li><strong>Cost estimates</strong> aligned to your expected traffic patterns and load</li></ul><p>Instead of “gut-feel” and partial information, teams can rely on a traceable evaluation record when choosing “the best model for our use case.”</p><h3 id="_5-tight-integration-with-the-ai-gateway" tabindex="-1">5. Tight Integration with the AI Gateway <a class="header-anchor" href="#_5-tight-integration-with-the-ai-gateway" aria-label="Permalink to &quot;5. Tight Integration with the AI Gateway&quot;">​</a></h3><p>Dori is directly coupled with the AI Gateway, so everything you discover and test is immediately available to integrate in production via:</p><ul><li><strong>One API key</strong></li><li><strong>One unified endpoint</strong></li><li><strong>A single, coherent API interface</strong></li></ul><p>Key consequences:</p><ul><li>You don’t need separate auth, SDKs, or endpoints per provider</li><li>A model you validate with Dori is ready to be used <strong>without adding a new vendor integration</strong></li><li>Changing models later becomes a ​<strong>configuration change</strong>​, not a redevelopment project</li></ul><h2 id="typical-use-cases" tabindex="-1">Typical Use Cases <a class="header-anchor" href="#typical-use-cases" aria-label="Permalink to &quot;Typical Use Cases&quot;">​</a></h2><h3 id="multilingual-customer-support" tabindex="-1">Multilingual Customer Support <a class="header-anchor" href="#multilingual-customer-support" aria-label="Permalink to &quot;Multilingual Customer Support&quot;">​</a></h3><ul><li>Need: Low-latency, cost-efficient LLM for a multilingual chatbot (e.g., English, Spanish, Portuguese)</li><li>How Dori helps: <ul><li>Interprets multilingual and latency requirements</li><li>Identifies models well-suited to conversational support across those languages</li><li>Lets you test using real customer queries and conversation flows</li></ul></li></ul><h3 id="code-assistants-and-developer-tools" tabindex="-1">Code Assistants and Developer Tools <a class="header-anchor" href="#code-assistants-and-developer-tools" aria-label="Permalink to &quot;Code Assistants and Developer Tools&quot;">​</a></h3><ul><li>Need: A model for code generation, explanation, and refactoring in languages like Python and TypeScript</li><li>How Dori helps: <ul><li>Highlights models with strong reasoning and coding capabilities</li><li>Emphasizes long-context support for large codebases</li><li>Facilitates trials using real repositories, code snippets, or tasks</li></ul></li></ul><h3 id="long-context-rag-and-document-applications" tabindex="-1">Long-Context RAG and Document Applications <a class="header-anchor" href="#long-context-rag-and-document-applications" aria-label="Permalink to &quot;Long-Context RAG and Document Applications&quot;">​</a></h3><ul><li>Need: Stable performance for long-document retrieval-augmented generation (RAG) with 10k+ token contexts</li><li>How Dori helps: <ul><li>Filters models by context length and RAG suitability</li><li>Allows evaluation with your actual documents and retrieval setup</li><li>Produces reports capturing both quality and performance under large contexts</li></ul></li></ul><h2 id="benefits-for-different-user-types" tabindex="-1">Benefits for Different User Types <a class="header-anchor" href="#benefits-for-different-user-types" aria-label="Permalink to &quot;Benefits for Different User Types&quot;">​</a></h2><h3 id="individual-developers-startup-teams" tabindex="-1">Individual Developers &amp; Startup Teams <a class="header-anchor" href="#individual-developers-startup-teams" aria-label="Permalink to &quot;Individual Developers &amp; Startup Teams&quot;">​</a></h3><ul><li>Focus on product and UX rather than: <ul><li>Chasing vendor docs</li><li>Wiring up multiple APIs and SDKs</li></ul></li><li>Iterate quickly: <ul><li>Try several models via Dori</li><li>Lock in one (or more) via the Marketplace</li><li>Swap later as new, better models arrive</li></ul></li></ul><h3 id="enterprises-large-platforms" tabindex="-1">Enterprises &amp; Large Platforms <a class="header-anchor" href="#enterprises-large-platforms" aria-label="Permalink to &quot;Enterprises &amp; Large Platforms&quot;">​</a></h3><ul><li>Standardize LLM access across business units using: <ul><li>A single integration with the LLM Marketplace</li><li>Shared evaluation workflows via Dori</li></ul></li><li>Reduce long-term maintenance: <ul><li>Avoid bespoke integrations per vendor</li><li>Maintain flexibility to adopt new models as the ecosystem evolves</li></ul></li></ul><h3 id="web3-and-on-chain-projects" tabindex="-1">Web3 and On-Chain Projects <a class="header-anchor" href="#web3-and-on-chain-projects" aria-label="Permalink to &quot;Web3 and On-Chain Projects&quot;">​</a></h3><ul><li>Build AI-powered agents, dApps, and protocols whose model backbone can: <ul><li>Upgrade over time</li><li>Diversify across providers</li></ul></li><li>Preserve on-chain and off-chain integration logic while: <ul><li>Changing or augmenting underlying LLMs via configuration</li><li>Avoiding breaking changes every time you adopt a new model</li></ul></li></ul>',44)]))}const g=a(r,[["render",n]]);export{p as __pageData,g as default};
